import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { 
  HomeIcon, 
  ClipboardDocumentListIcon, 
  ShoppingBagIcon, 
  CogIcon,
  PlusIcon,
  PencilIcon,
  TrashIcon
} from '@heroicons/react/24/outline';
import { dishAPI, restaurantAPI } from '../services/api';

const OwnerDashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [dishes, setDishes] = useState([]);
  const [restaurant, setRestaurant] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [editingDish, setEditingDish] = useState(null);
  const [formData, setFormData] = useState({
    dishName: '',
    price: '',
    veg: true
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [dishesRes, restaurantsRes] = await Promise.all([
        dishAPI.getAll(),
        restaurantAPI.getAll()
      ]);
      setDishes(dishesRes.data);
      const userRestaurant = restaurantsRes.data.find(r => r.ownerId === user.id);
      setRestaurant(userRestaurant);
    } catch (error) {
      console.error('Error loading data:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingDish) {
        await dishAPI.update(editingDish.id, formData);
      } else {
        await dishAPI.add({ ...formData, restaurantId: restaurant?.id });
      }
      loadData();
      setShowModal(false);
      setEditingDish(null);
      setFormData({ dishName: '', price: '', veg: true });
    } catch (error) {
      alert('Error saving dish');
    }
  };

  const handleEdit = (dish) => {
    setEditingDish(dish);
    setFormData({
      dishName: dish.dishName,
      price: dish.price,
      veg: dish.veg
    });
    setShowModal(true);
  };

  const handleDelete = async (dishId) => {
    if (window.confirm('Delete this dish?')) {
      try {
        await dishAPI.delete(dishId);
        loadData();
      } catch (error) {
        alert('Error deleting dish');
      }
    }
  };

  const sidebarItems = [
    { id: 'dashboard', label: 'Dashboard', icon: HomeIcon },
    { id: 'menu', label: 'Menu', icon: ClipboardDocumentListIcon },
    { id: 'orders', label: 'Orders', icon: ShoppingBagIcon },
    { id: 'settings', label: 'Settings', icon: CogIcon }
  ];

  const stats = [
    { label: 'Total Dishes', value: dishes.length, color: 'from-blue-500 to-blue-600', icon: '🍽️' },
    { label: 'Orders Today', value: Math.floor(Math.random() * 50) + 10, color: 'from-green-500 to-green-600', icon: '📦' },
    { label: 'Reviews', value: Math.floor(Math.random() * 100) + 20, color: 'from-purple-500 to-purple-600', icon: '⭐' },
    { label: 'Revenue', value: `₹${Math.floor(Math.random() * 10000) + 5000}`, color: 'from-orange-500 to-orange-600', icon: '💰' }
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex">
      {/* Sidebar */}
      <div className="w-64 bg-white shadow-lg">
        <div className="p-6 border-b">
          <h1 className="text-xl font-bold bg-gradient-to-r from-orange-500 to-red-500 bg-clip-text text-transparent">
            🍔 SnackSmart
          </h1>
          <p className="text-sm text-gray-600 mt-1">Owner Panel</p>
        </div>

        <nav className="mt-6">
          {sidebarItems.map((item) => (
            <motion.button
              key={item.id}
              whileHover={{ x: 4 }}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
                activeTab === item.id
                  ? 'bg-orange-50 text-orange-600 border-r-2 border-orange-600'
                  : 'text-gray-600 hover:bg-gray-50'
              }`}
            >
              <item.icon className="h-5 w-5 mr-3" />
              {item.label}
            </motion.button>
          ))}
        </nav>

        <div className="absolute bottom-6 left-6 right-6">
          <div className="text-center mb-4">
            <div className="w-12 h-12 bg-gradient-to-r from-orange-500 to-red-500 rounded-full flex items-center justify-center text-white font-bold mx-auto mb-2">
              {user.username?.charAt(0).toUpperCase()}
            </div>
            <p className="text-sm font-medium">{user.username}</p>
          </div>
          <motion.button
            whileHover={{ scale: 1.02 }}
            onClick={onLogout}
            className="w-full bg-red-500 text-white py-2 rounded-lg hover:bg-red-600 transition-colors"
          >
            Logout
          </motion.button>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-8">
        {activeTab === 'dashboard' && (
          <div>
            <h2 className="text-3xl font-bold text-gray-900 mb-8">Dashboard</h2>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
              {stats.map((stat, index) => (
                <motion.div
                  key={index}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.1 }}
                  className={`bg-gradient-to-r ${stat.color} rounded-2xl p-6 text-white`}
                >
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-white/80 text-sm">{stat.label}</p>
                      <p className="text-2xl font-bold">{stat.value}</p>
                    </div>
                    <div className="text-3xl">{stat.icon}</div>
                  </div>
                </motion.div>
              ))}
            </div>

            {/* Restaurant Info */}
            {restaurant && (
              <div className="bg-white rounded-2xl shadow-sm p-6">
                <h3 className="text-xl font-semibold mb-4">Restaurant Information</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <p className="text-sm text-gray-600">Name</p>
                    <p className="font-medium">{restaurant.name}</p>
                  </div>
                  <div>
                    <p className="text-sm text-gray-600">Address</p>
                    <p className="font-medium">{restaurant.address}</p>
                  </div>
                  <div>
                    <p className="text-sm text-gray-600">Phone</p>
                    <p className="font-medium">{restaurant.phone}</p>
                  </div>
                  <div>
                    <p className="text-sm text-gray-600">Rating</p>
                    <p className="font-medium">⭐ {restaurant.rating || '4.0'}/5</p>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {activeTab === 'menu' && (
          <div>
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-bold text-gray-900">Menu Management</h2>
              <motion.button
                whileHover={{ scale: 1.05 }}
                onClick={() => setShowModal(true)}
                className="bg-gradient-to-r from-orange-500 to-red-500 text-white px-6 py-3 rounded-xl font-medium shadow-lg hover:shadow-xl transition-all flex items-center"
              >
                <PlusIcon className="h-5 w-5 mr-2" />
                Add Dish
              </motion.button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {dishes.map((dish, index) => (
                <motion.div
                  key={dish.id}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.1 }}
                  className="bg-white rounded-2xl shadow-sm p-6 hover:shadow-md transition-shadow"
                >
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h3 className="font-semibold text-lg">{dish.dishName}</h3>
                      <p className="text-green-600 font-bold">₹{dish.price}</p>
                    </div>
                    <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                      dish.veg ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                    }`}>
                      {dish.veg ? '🌿 Veg' : '🍗 Non-Veg'}
                    </span>
                  </div>

                  <div className="flex space-x-2">
                    <motion.button
                      whileHover={{ scale: 1.05 }}
                      onClick={() => handleEdit(dish)}
                      className="flex-1 bg-blue-500 text-white py-2 rounded-lg hover:bg-blue-600 transition-colors flex items-center justify-center"
                    >
                      <PencilIcon className="h-4 w-4 mr-1" />
                      Edit
                    </motion.button>
                    <motion.button
                      whileHover={{ scale: 1.05 }}
                      onClick={() => handleDelete(dish.id)}
                      className="flex-1 bg-red-500 text-white py-2 rounded-lg hover:bg-red-600 transition-colors flex items-center justify-center"
                    >
                      <TrashIcon className="h-4 w-4 mr-1" />
                      Delete
                    </motion.button>
                  </div>
                </motion.div>
              ))}
            </div>

            {dishes.length === 0 && (
              <div className="text-center py-16">
                <div className="text-6xl mb-4">🍽️</div>
                <h3 className="text-xl font-semibold text-gray-900 mb-2">No dishes yet</h3>
                <p className="text-gray-600">Add your first dish to get started</p>
              </div>
            )}
          </div>
        )}

        {activeTab === 'orders' && (
          <div>
            <h2 className="text-3xl font-bold text-gray-900 mb-8">Orders</h2>
            <div className="text-center py-16">
              <div className="text-6xl mb-4">📦</div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">Orders feature coming soon</h3>
              <p className="text-gray-600">Track and manage your restaurant orders</p>
            </div>
          </div>
        )}

        {activeTab === 'settings' && (
          <div>
            <h2 className="text-3xl font-bold text-gray-900 mb-8">Settings</h2>
            <div className="text-center py-16">
              <div className="text-6xl mb-4">⚙️</div>
              <h3 className="text-xl font-semibold text-gray-900 mb-2">Settings coming soon</h3>
              <p className="text-gray-600">Manage your restaurant settings and preferences</p>
            </div>
          </div>
        )}
      </div>

      {/* Add/Edit Dish Modal */}
      {showModal && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50"
          onClick={() => setShowModal(false)}
        >
          <motion.div
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="bg-white rounded-2xl p-6 w-full max-w-md"
            onClick={(e) => e.stopPropagation()}
          >
            <h3 className="text-xl font-semibold mb-4">
              {editingDish ? 'Edit Dish' : 'Add New Dish'}
            </h3>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Dish Name</label>
                <input
                  type="text"
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  value={formData.dishName}
                  onChange={(e) => setFormData({...formData, dishName: e.target.value})}
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Price (₹)</label>
                <input
                  type="number"
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  value={formData.price}
                  onChange={(e) => setFormData({...formData, price: e.target.value})}
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
                <select
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  value={formData.veg}
                  onChange={(e) => setFormData({...formData, veg: e.target.value === 'true'})}
                >
                  <option value="true">Vegetarian</option>
                  <option value="false">Non-Vegetarian</option>
                </select>
              </div>

              <div className="flex space-x-3 pt-4">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="flex-1 px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="flex-1 bg-gradient-to-r from-orange-500 to-red-500 text-white px-4 py-2 rounded-lg hover:shadow-lg transition-all"
                >
                  {editingDish ? 'Update' : 'Add'} Dish
                </button>
              </div>
            </form>
          </motion.div>
        </motion.div>
      )}
    </div>
  );
};

export default OwnerDashboard;
